using System;
using System.Collections.Generic;
using System.Xml;

public class XmlConfigParser
{
    public Dictionary<string, string> ParseXmlConfig(string xmlContent)
    {
        var settings = new Dictionary<string, string>();
        var xmlSettings = new XmlReaderSettings
        {
            DtdProcessing = DtdProcessing.Parse,
            ValidationType = ValidationType.DTD
        };

        using (var reader = XmlReader.Create(new System.IO.StringReader(xmlContent), xmlSettings))
        {
            var doc = new XmlDocument();
            doc.Load(reader);

            XmlNodeList settingNodes = doc.SelectNodes("//settings/setting");
            if (settingNodes != null)
            {
                foreach (XmlNode node in settingNodes)
                {
                    var key = node.Attributes["key"]?.InnerText;
                    var value = node.Attributes["value"]?.InnerText;
                    if (key != null && value != null)
                    {
                        settings[key] = value;
                    }
                }
            }
        }

        return settings;
    }
}